import{a,S as s}from"./skill-Cdo-XAtV.js";class c{constructor(e){this.id=e?.id??"phone_screen",this.name=e?.name??"Phone Screen Control",this.category=e?.category??"Device Automation",this.description=e?.description??"View and control the Android phone screen via accessibility service.",this.tools=e?.tools?.map(t=>({name:t.name,description:t.description,parameters:t.parameters}))??[]}async execute(e,t){switch(e){case"phone_wait":{const i=Number(t.durationMs)||1e3;return await new Promise(r=>setTimeout(r,Math.min(i,1e4))),s(`Waited ${i}ms`,{action:"wait",durationMs:i})}case"phone_done":{const i=t.summary??"Task completed";return s(i,{action:"done",message:i})}default:return a(`Tool "${e}" requires native phone accessibility service (not yet wired).`)}}}export{c as PhoneScreenSkill};
